    """
    Rejects oversized requests before multipart parsing can consume excessive
    memory, temp space, or worker time. Also handles chunked uploads with no
    Content-Length by counting bytes from the ASGI receive stream.
    """

    def __init__(self, app: ASGIApp, max_bytes: int):
        self.app = app
        self.max_bytes = max_bytes

    async def __call__(self, scope: Scope, receive: Receive, send: Send) -> None:
        if (
            scope["type"] != "http"
            or scope.get("path") != "/api/upload"
            or scope.get("method") != "POST"
        ):
            await self.app(scope, receive, send)
            return

        request_id = uuid.uuid4().hex
        scope.setdefault("state", {})["request_id"] = request_id

        client = scope.get("client")
        client_ip = client[0] if client else "unknown"

        headers = {k.lower(): v for k, v in scope.get("headers", [])}
        content_length_raw = headers.get(b"content-length")

        logger.info(
            "upload_attempt_started request_id=%s client=%s content_length=%s",
            request_id,
            client_ip,
            content_length_raw.decode("ascii", "ignore") if content_length_raw else None,
        )

        if content_length_raw:
            try:
                content_length = int(content_length_raw)
            except ValueError:
                logger.warning(
                    "upload_failed request_id=%s code=INVALID_CONTENT_LENGTH",
                    request_id,
                )
                await send_asgi_json(
                    send,
                    request_id,
                    400,
                    "INVALID_CONTENT_LENGTH",
                    "Content-Length must be a valid integer.",
                )
                return

            if content_length > self.max_bytes:
                logger.warning(
                    "upload_failed request_id=%s code=REQUEST_TOO_LARGE size=%s",
                    request_id,
                    content_length,
                )
                await send_asgi_json(
                    send,
                    request_id,
                    413,
                    "REQUEST_TOO_LARGE",
                    "Request body exceeds the maximum allowed upload size.",
                    {"max_file_size": MAX_FILE_SIZE},
                )
                return

        received = 0
        response_started = False

        async def limited_receive() -> Message:
            nonlocal received

            message = await receive()
            if message["type"] == "http.request":
                received += len(message.get("body", b""))
                if received > self.max_bytes:
                    raise BodyTooLarge()
            return message

        async def tracking_send(message: Message) -> None:
            nonlocal response_started
            if message["type"] == "http.response.start":
                response_started = True
            await send(message)

        try:
            await self.app(scope, limited_receive, tracking_send)
        except BodyTooLarge:
            logger.warning(
                "upload_failed request_id=%s code=REQUEST_TOO_LARGE streamed_size>%s",
                request_id,
                self.max_bytes,
            )
            if not response_started:
