def detect_image_kind(header: bytes) -> Optional[ImageKind]:
    """
    Validates MIME type using magic bytes, not client filename or Content-Type.
    """

    if header.startswith(b"\xff\xd8\xff"):
        return JPEG

    if header.startswith(b"\x89PNG\r\n\x1a\n") and len(header) >= 24 and header[12:16] == b"IHDR":
        return PNG

    if header.startswith((b"GIF87a", b"GIF89a")):
        return GIF

    if (
        len(header) >= 16
        and header[0:4] == b"RIFF"
        and header[8:12] == b"WEBP"
        and header[12:16] in {b"VP8 ", b"VP8L", b"VP8X"}
    ):
        return WEBP

    return None


def validate_declared_content_type(declared: Optional[str], detected: ImageKind) -> None:
    """
    Rejects unsupported or contradictory client-declared MIME types while still
    allowing generic binary upload clients.
    """

    normalized = (declared or "").split(";", 1)[0].strip().lower()
    expected = ALLOWED_MIME_ALIASES.get(normalized, "__unsupported__")

    if expected == "__unsupported__":
        raise UploadError(
            415,
            "UNSUPPORTED_MEDIA_TYPE",
            "Content-Type is not an allowed image type.",
            {"content_type": declared},
        )

    if expected is not None and expected != detected.mime:
        raise UploadError(
            415,
            "MIME_MISMATCH",
            "Content-Type does not match the uploaded file signature.",
            {"declared": declared, "detected": detected.mime},
        )


def sanitize_filename(original: Optional[str], ext: str) -> str:
    """
    Prevents path traversal, Windows device names, null bytes, control chars,
    hidden dotfiles, alternate data streams, double extensions, and very long
    names. The final storage name is still random; this is safe display metadata.
    """

    name = original or "upload"
    name = name.replace("\x00", "")
    name = name.replace("\\", "/").rsplit("/", 1)[-1]
    name = unicodedata.normalize("NFKC", name)

    while True:
        stem, suffix = os.path.splitext(name)
        if not suffix:
            break
        name = stem

    name = "".join(ch for ch in name if ch.isprintable())
    name = re.sub(r"[^A-Za-z0-9._-]+", "_", name)
    name = re.sub(r"_+", "_", name).strip(" ._-")

    reserved = {
        "CON", "PRN", "AUX", "NUL",
        *(f"COM{i}" for i in range(1, 10)),
        *(f"LPT{i}" for i in range(1, 10)),
    }

    if not name or name.upper() in reserved:
        name = "upload"

    return f"{name[:80]}{ext}"


def validate_image_trailer(kind: ImageKind, first_chunk: bytes, tail: bytes, total: int) -> None:
    """
    Catches truncated files and simple polyglot/appended-payload tricks.
    """

    if kind is JPEG and not tail.endswith(b"\xff\xd9"):
        raise UploadError(400, "TRUNCATED_IMAGE", "JPEG is missing its end marker.")

    if kind is PNG and not tail.endswith(PNG_IEND):
        raise UploadError(400, "TRUNCATED_IMAGE", "PNG is missing its IEND chunk.")

    if kind is GIF and not tail.endswith(b";"):
        raise UploadError(400, "TRUNCATED_IMAGE", "GIF is missing its trailer byte.")

    if kind is WEBP:
        expected_size = int.from_bytes(first_chunk[4:8], "little") + 8
        if expected_size != total:
            raise UploadError(
                400,
                "INVALID_IMAGE",
                "WebP RIFF size does not match actual file size.",
                {"expected_size": expected_size, "actual_size": total},
            )


def verify_with_pillow(path: Path, kind: ImageKind) -> dict[str, Any]:
    """
    Performs deeper image validation without loading the upload into memory.
    Also blocks decompression bombs by enforcing a pixel limit.
    """

    if not PIL_AVAILABLE:
        return {"verified": False, "reason": "pillow_not_installed"}

    if kind is WEBP and features is not None and not features.check("webp"):
        return {"verified": False, "reason": "webp_not_supported_by_pillow"}

    try:
        with Image.open(path) as img:
            width, height = img.size
            image_format = img.format

            if image_format != kind.pillow_format:
                raise UploadError(
                    400,
                    "IMAGE_FORMAT_MISMATCH",
                    "Decoded image format does not match magic-byte detection.",
                    {"decoded": image_format, "detected": kind.mime},
                )

            if width <= 0 or height <= 0:
                raise UploadError(400, "INVALID_IMAGE_DIMENSIONS", "Image dimensions are invalid.")

            if width * height > 50_000_000:
                raise UploadError(
                    413,
                    "IMAGE_DIMENSIONS_TOO_LARGE",
                    "Image dimensions exceed the configured safety limit.",
                    {"width": width, "height": height},
                )

            img.verify()

            return {
                "verified": True,
                "width": width,
                "height": height,
                "format": image_format,
            }

    except UploadError:
        raise
    except Image.DecompressionBombError as exc:
        raise UploadError(413, "IMAGE_DIMENSIONS_TOO_LARGE", str(exc))
    except (UnidentifiedImageError, OSError, SyntaxError) as exc:
        raise UploadError(400, "INVALID_IMAGE", "Uploaded file is not a valid image.", {"reason": str(exc)})


def write_all(fd: int, data: bytes) -> None:
    """
    Handles partial writes and interrupted syscalls explicitly.
    """

    view = memoryview(data)
    while view:
        try:
            written = os.write(fd, view)
        except InterruptedError:
            continue

        if written == 0:
            raise OSError(errno.EIO, "write returned zero bytes")

        view = view[written:]


def fsync_directory(path: Path) -> None:
    """
    Persists the rename metadata where supported.
    """

    if not hasattr(os, "O_DIRECTORY"):
        return

    fd = os.open(path, os.O_RDONLY | os.O_DIRECTORY)
    try:
        os.fsync(fd)
    finally:
        os.close(fd)


def atomic_promote(tmp_path: Path, final_path: Path) -> None:
    """
    Atomically publishes the completed temp file. os.link avoids overwriting an
    existing file if an improbable random-name collision occurs.
    """

    try:
        os.link(tmp_path, final_path)
        os.unlink(tmp_path)
    except FileExistsError:
        raise UploadError(500, "FILENAME_COLLISION", "Generated upload filename collided.")
    except OSError:
        if final_path.exists():
            raise UploadError(500, "FILENAME_COLLISION", "Generated upload filename collided.")
        os.replace(tmp_path, final_path)


def storage_error(exc: OSError, default_code: str = "STORAGE_WRITE_FAILED") -> UploadError:
    if exc.errno in {errno.ENOSPC, getattr(errno, "EDQUOT", errno.ENOSPC)}:
        return UploadError(500, "INSUFFICIENT_STORAGE", "Upload storage is full.")
    if exc.errno in {errno.EACCES, errno.EPERM, errno.EROFS}:
        return UploadError(500, "STORAGE_PERMISSION_DENIED", "Upload storage is not writable.")
    return UploadError(500, default_code, "Upload could not be written to storage.", {"reason": str(exc)})


