async def parse_form(request: Request) -> FormData:
    kwargs = {"max_files": MAX_FILES, "max_fields": MAX_FIELDS}
    if "max_part_size" in inspect.signature(Request.form).parameters:
        kwargs["max_part_size"] = MAX_FILE_SIZE

