        raise UploadError(400, "CLIENT_DISCONNECTED", "Client disconnected during upload.")
    except MultiPartException as exc:
        message = str(exc)
        code = "MALFORMED_MULTIPART"
        status = 400

        if "files" in message.lower():
            code = "TOO_MANY_FILES"
        elif "fields" in message.lower():
            code = "TOO_MANY_FIELDS"
        elif "size" in message.lower():
            code = "REQUEST_TOO_LARGE"
            status = 413

