def extract_single_file(form: FormData) -> UploadFile:
    files = [(key, value) for key, value in form.multi_items() if isinstance(value, UploadFile)]

    if not files:
        raise UploadError(400, "MISSING_FILE", "Expected one file field named 'file'.")

    if len(files) > 1:
        raise UploadError(400, "TOO_MANY_FILES", "Only one uploaded file is allowed.")

    field_name, file = files[0]

    if field_name != "file":
        raise UploadError(400, "INVALID_FILE_FIELD", "Upload field must be named 'file'.")

    if not file.filename or not file.filename.strip():
        raise UploadError(400, "EMPTY_FILENAME", "Uploaded file must have a filename.")

    return file


async def persist_upload(file: UploadFile) -> dict[str, Any]:
