    if not first_chunk:
        raise UploadError(400, "EMPTY_FILE", "Uploaded file is empty.")

    kind = detect_image_kind(first_chunk)
    if kind is None:
        raise UploadError(
            415,
            "UNSUPPORTED_FILE_TYPE",
            "Only JPEG, PNG, GIF, and WebP uploads are allowed.",
        )

    validate_declared_content_type(file.content_type, kind)

    safe_original_name = sanitize_filename(file.filename, kind.ext)

    ensure_storage_dirs()

    try:
        free = shutil.disk_usage(UPLOAD_DIR).free
    except OSError as exc:
        raise storage_error(exc, "STORAGE_CHECK_FAILED")

    if free < MAX_FILE_SIZE + MIN_FREE_BYTES:
        raise UploadError(500, "INSUFFICIENT_STORAGE", "Not enough free disk space for uploads.")

    file_id = secrets.token_hex(16)
    stored_name = f"{file_id}{kind.ext}"
    final_path = (UPLOAD_DIR / stored_name).resolve()

    if final_path.parent != UPLOAD_DIR:
        raise UploadError(500, "STORAGE_PATH_INVALID", "Resolved upload path escaped storage root.")

    fd: Optional[int] = None
    tmp_path: Optional[Path] = None

    sha256 = hashlib.sha256()
    total = 0
    tail = b""

    try:
        fd, tmp_name = tempfile.mkstemp(prefix=".upload-", suffix=".tmp", dir=TMP_DIR)
        tmp_path = Path(tmp_name)

        chunk = first_chunk
        while chunk:
            if total + len(chunk) > MAX_FILE_SIZE:
                raise UploadError(
                    413,
                    "FILE_TOO_LARGE",
                    "Uploaded file exceeds the 10MB limit.",
                    {"max_file_size": MAX_FILE_SIZE},
