            await asyncio.to_thread(write_all, fd, chunk)

            total += len(chunk)
            sha256.update(chunk)
            tail = (tail + chunk)[-32:]

            chunk = await read_chunk(file)

        validate_image_trailer(kind, first_chunk, tail, total)

        await asyncio.to_thread(os.fsync, fd)
        await asyncio.to_thread(os.close, fd)
        fd = None

        image_meta = await asyncio.to_thread(verify_with_pillow, tmp_path, kind)

        await asyncio.to_thread(atomic_promote, tmp_path, final_path)
        tmp_path = None

        try:
            await asyncio.to_thread(fsync_directory, UPLOAD_DIR)
        except OSError:
            logger.warning("upload_directory_fsync_failed path=%s", UPLOAD_DIR, exc_info=True)

        return {
            "id": file_id,
            "stored_name": stored_name,
            "original_filename": file.filename,
            "safe_filename": safe_original_name,
            "content_type": kind.mime,
            "size": total,
            "sha256": sha256.hexdigest(),
            "image": image_meta,
        }

    except UploadError:
        raise
    except OSError as exc:
        raise storage_error(exc)
    finally:
        if fd is not None:
            try:
                os.close(fd)
            except OSError:
                pass

        if tmp_path is not None:
            try:
                tmp_path.unlink(missing_ok=True)
            except OSError:
                logger.warning("temp_cleanup_failed path=%s", tmp_path, exc_info=True)


